#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define grep(b,c) for(int c(head[b]);c;c=nxt[c])
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
typedef long long ll;
const int N=1e6+10;
const ll INF=1e18;
struct Node
{
	int v,w,p;
	inline bool operator < (const Node &Q)const{return w==Q.w?(v==Q.v?p<Q.p:v<Q.v):w>Q.w;}
	inline bool operator ==(const Node &Q)const{return v==Q.v&&w==Q.w&&p==Q.p;}
};
struct NODE{int u,v,w,p;}a[N];
int n,m,deg[N];ll f[N];
set<Node> G[N];
int main()
{
	n=read();m=read();rep(1,n,i)f[i]=INF;
	rep(1,m,i)
	{
		int v=a[i].v=read(),u=a[i].u=read(),w=a[i].w=read(),p=a[i].p=read();
		if(!G[u].count({v,w,p}))G[u].insert({v,w,p}),++deg[v];
	}
	sort(a+1,a+m+1,[&](NODE x,NODE y){return x.w>y.w;});
	queue<int> q;
	rep(1,n,i)if(!deg[i])q.push(i);
	for(int i=1;i<=m||!q.empty();++i)
	{
		while(!q.empty())
		{
			int u=q.front();q.pop();
			for(auto x:G[u])
			{
				if(f[u]!=INF)f[x.v]=min(f[x.v],max(0ll+x.w,f[u]-x.p));
				if(!(--deg[x.v]))q.push(x.v);
			}
			G[u].clear();
		}
		if(i>m)break;
		if(!G[a[i].u].count({a[i].v,a[i].w,a[i].p}))continue;
//		f[a[i].u]=min(f[a[i].u],0ll+a[i].w);
		f[a[i].v]=min(f[a[i].v],a[i].w+0ll);
		G[a[i].u].erase({a[i].v,a[i].w,a[i].p});
		if(!(--deg[a[i].v]))q.push(a[i].v);
	}
	rep(1,n,i)printf("%lld ",f[i]==INF?-1ll:f[i]);puts("");
}
